import { afterEach, describe, expect, it } from "vitest";

import {
  buildClearedSessionCookie,
  buildSessionCookie,
  getSessionToken,
} from "./session";

const originalNodeEnv = process.env.NODE_ENV;
const mutableEnv = process.env as Record<string, string | undefined>;

afterEach(() => {
  mutableEnv.NODE_ENV = originalNodeEnv;
});

describe("session helpers", () => {
  it("builds an http-only cookie definition for local development", () => {
    mutableEnv.NODE_ENV = "development";

    expect(buildSessionCookie("token-123")).toEqual({
      name: "skynet_access_token",
      value: "token-123",
      httpOnly: true,
      sameSite: "lax",
      secure: false,
      path: "/",
      maxAge: 3600,
    });
  });

  it("marks the session cookie as secure in production", () => {
    mutableEnv.NODE_ENV = "production";
    expect(buildSessionCookie("token-123").secure).toBe(true);
  });

  it("builds an expiring cookie definition for logout", () => {
    mutableEnv.NODE_ENV = "development";

    expect(buildClearedSessionCookie()).toEqual({
      name: "skynet_access_token",
      value: "",
      httpOnly: true,
      sameSite: "lax",
      secure: false,
      path: "/",
      maxAge: 0,
    });
  });

  it("reads session token from request cookies", () => {
    const token = getSessionToken({
      cookies: {
        get(name: string) {
          return name === "skynet_access_token" ? { value: "cookie-token" } : undefined;
        },
      },
    });

    expect(token).toBe("cookie-token");
  });

  it("returns null when session cookie is missing", () => {
    const token = getSessionToken({
      cookies: {
        get() {
          return undefined;
        },
      },
    });

    expect(token).toBeNull();
  });
});

import { afterAll, beforeAll, describe, expect, it } from "vitest";

import { signAccessToken, verifyAccessToken } from "./jwt";

const originalJwtSecret = process.env.JWT_SECRET;

describe("jwt helpers", () => {
  beforeAll(() => {
    process.env.JWT_SECRET = "test-jwt-secret-value";
  });

  afterAll(() => {
    if (originalJwtSecret === undefined) {
      delete process.env.JWT_SECRET;
      return;
    }

    process.env.JWT_SECRET = originalJwtSecret;
  });

  it("signs and verifies an access token", async () => {
    const token = await signAccessToken({
      sub: "user_123",
      username: "momo",
      role: "engineer",
    });

    const payload = await verifyAccessToken(token);
    expect(payload).not.toBeNull();
    expect(payload?.sub).toBe("user_123");
    expect(payload?.username).toBe("momo");
  });

  it("returns null for malformed token", async () => {
    const payload = await verifyAccessToken("not-a-jwt");
    expect(payload).toBeNull();
  });
});

import { describe, expect, it } from "vitest";

import { getRequestToken } from "./request-token";

describe("getRequestToken", () => {
  it("returns Bearer token from authorization header first", () => {
    const token = getRequestToken({
      headers: {
        get(name: string) {
          return name === "authorization" ? "Bearer header-token" : null;
        },
      },
      cookies: {
        get() {
          return { value: "cookie-token" };
        },
      },
    });

    expect(token).toBe("header-token");
  });

  it("falls back to session cookie when authorization header is missing", () => {
    const token = getRequestToken({
      headers: {
        get() {
          return null;
        },
      },
      cookies: {
        get(name: string) {
          return name === "skynet_access_token" ? { value: "cookie-token" } : undefined;
        },
      },
    });

    expect(token).toBe("cookie-token");
  });

  it("returns null when neither bearer header nor cookie exists", () => {
    const token = getRequestToken({
      headers: {
        get() {
          return null;
        },
      },
      cookies: {
        get() {
          return undefined;
        },
      },
    });

    expect(token).toBeNull();
  });
});

